class LoggerTrampoline : public calc::Logger {
public:
    explicit LoggerTrampoline(int32_t callback_id) : _callback_id(callback_id) {}
    ~LoggerTrampoline() override = default;
    int32_t level() const override {
        ProtoWriter _pw;
        int64_t _rc = wasmify_callback_invoke(_callback_id, 0, _pw.data_, _pw.size_);
        uintptr_t _resp_ptr = static_cast<uintptr_t>(static_cast<uint64_t>(_rc) >> 32);
        int32_t _resp_len = static_cast<int32_t>(_rc & 0xFFFFFFFFu);
        int32_t _result = {};
        if (_resp_ptr != 0) {
            ProtoReader _pr(reinterpret_cast<const void*>(_resp_ptr), _resp_len);
            while (_pr.next()) {
                if (_pr.field() == 1) {
                    _result = _pr.read_int32();
                } else {
                    _pr.skip();
                }
            }
            wasm_free(reinterpret_cast<void*>(_resp_ptr));
        }
        return _result;
    }
    void log(const std::string& message) override {
        ProtoWriter _pw;
        _pw.write_string(1, message);
        int64_t _rc = wasmify_callback_invoke(_callback_id, 1, _pw.data_, _pw.size_);
        uintptr_t _resp_ptr = static_cast<uintptr_t>(static_cast<uint64_t>(_rc) >> 32);
        int32_t _resp_len = static_cast<int32_t>(_rc & 0xFFFFFFFFu);
        if (_resp_ptr != 0) wasm_free(reinterpret_cast<void*>(_resp_ptr));
    }
private:
    int32_t _callback_id;
};

