// ======================================
// Value-type submessage parsers
// ======================================

static void parse_calc__Result(ProtoReader reader, calc::Result& out) {
    while (reader.has_data() && reader.next()) {
        switch (reader.field()) {
        case 1: {
            out.error_message = reader.read_string();
            break;
        }
        case 2: {
            out.ok = reader.read_bool();
            break;
        }
        case 3: {
            out.value = reader.read_double();
            break;
        }
        default: reader.skip(); break;
        }
    }
}

